export default function RentCalculator(){useCurrencyVersion();const[income,setIncome]=useState(5000),[utilities,setUtilities]=useState(200);const rent30=income*.30,rent28=income*.28,needsBudget=income*.50,recommended=Math.max(0,Math.min(rent30,needsBudget-utilities));const rows=[2000,3000,4000,5000,7500,10000].map(i=>({i,r30:i*.3,r28:i*.28,withUtil:i*.3-200,annual:i*.3*12}));const inputClass="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";return <><SEOHead title="Free Rent Calculator Online - Calculate How Much Rent You Can Afford Instantly | CalcHive" description="Free online rent calculator. Calculate the maximum rent you can afford based on your income using the 30% rule and 50/30/20 budget instantly. 100% free, no signup required." canonical="/rent-calculator" keywords="free rent calculator, how much rent can I afford calculator free, rent affordability calculator free online, 30 percent rule rent calculator free, monthly rent budget calculator free" category="Financial Calculators" breadcrumbName="Free Rent Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS}/><main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Rent Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate how much rent you can afford using the 30% rule, 28% rule, and 50/30/20 budget guideline.</p></div><AdPlaceholder size="banner" className="mb-8"/><section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Monthly gross income</label><input type="number" value={income} onChange={e=>setIncome(Number(e.target.value))} className={inputClass}/></div><div><label className="text-sm font-semibold text-foreground block mb-2">Estimated utilities</label><input type="number" value={utilities} onChange={e=>setUtilities(Number(e.target.value))} className={inputClass}/></div></div><motion.div key={`${income}-${utilities}`} initial={{opacity:.7,y:4}} animate={{opacity:1,y:0}}><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Recommended Max Rent</p><p className="text-5xl sm:text-6xl font-black text-white" data-testid="result-rent">{money(recommended)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["30% rule",money(rent30)],["28% rule",money(rent28)],["Housing + utilities",money(recommended+utilities)]].map(([l,v])=><div key={l} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">{l}</p><p className="text-lg font-extrabold text-foreground">{v}</p></div>)}</div></motion.div></section><ShareButton/><section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate How Much Rent You Can Afford for Free</h2><p className="text-muted-foreground leading-relaxed">This rent affordability calculator free online compares multiple budget rules and includes utilities in your total housing costs.</p><h2 className="text-2xl font-bold text-foreground">The 30 Percent Rule and Other Rent Affordability Guidelines</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Recommended Maximum Rent by Income</caption><thead className="bg-muted/60"><tr>{["Monthly Income","30% Rule Max Rent","28% Rule Max Rent","With $200 Utilities","Annual Rent Cost"].map(h=><th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map(r=><tr key={r.i}><td className="py-2.5 px-3 font-semibold">{money(r.i)}</td><td className="py-2.5 px-3">{money(r.r30)}</td><td className="py-2.5 px-3">{money(r.r28)}</td><td className="py-2.5 px-3">{money(r.withUtil)}</td><td className="py-2.5 px-3">{money(r.annual)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Rent Affordability Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this monthly rent budget calculator free to compare rent with utilities and income.</p></section><section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map(f=><FAQItem key={f.q} q={f.q} a={f.a}/>)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8"/><RelatedTools exclude="/rent-calculator" headingLevel="h3"/></main></>;}


